var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체와는 예전에도 몇 번 싸워 본 적이 있어요.","JPN":"侵食体とは以前にも何回か戦ったことがあります。","ENG":"I had fought C.O.s a few times before then.","TWN":"我之前也跟侵蝕體戰鬥過。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"돈을 벌려고 침식지대에서 희생자들의 유품을 수거하는 일을 몰래 해 봤거든요.","JPN":"お金を稼ぐため、侵食地帯で犠牲者の遺品を収集する仕事をこっそりしていたんですよ。","ENG":"I used to sneak out to Corrupted Areas to forage for valuables among the victims to make an extra buck.","TWN":"為了賺錢，曾經偷偷在侵蝕地區回收過犧牲者的遺物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그렇게 많은 침식체들과 싸워 본 건 그 때가 처음이었어요.","JPN":"でもあんな大勢の侵食体と戦ったのは、あの時が初めてでした。","ENG":"But I never fought so many C.O.s until that day.","TWN":"但跟那麼多侵蝕體戰鬥，那次是第一次。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"속이 메스꺼워...... 벌써 지치면 안 되는데......","JPN":"気持ち悪くて吐きそう……でも疲れるにはまだ早い……","ENG":"I feel nauseous... But it's too early to give up now...","TWN":"噁呃……不能這麼快就倒下……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"팔이 아파...... 덩실이도 너무 무거워......","JPN":"腕が痛い……ふわりも重すぎる……","ENG":"My arms are sore... Dangler never felt so heavy...","TWN":"胳膊好疼……鐮刀也變得好沉重啊……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으앗?!","JPN":"わあっ！！","ENG":"Huh?!","TWN":"呃啊？！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SLASH_BIG"},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"타이런트? 도망칠 길이 막혔어......?","JPN":"タイラント？　逃げ道がない……？","ENG":"A Tyrant? It cut off my escape route!","TWN":"那是侵蝕體暴君？逃走的路被堵住了……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"읏......","JPN":"うっ……","ENG":"Ugh...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"무서워서 다리가 풀린다는 말이 무슨 뜻인지, 그 때 처음으로 알았어요.","JPN":"恐怖で足の力が抜けるという言葉の意味を、あの時初めて知りました。","ENG":"That's when I realized what it means to have your legs go weak from fear.","TWN":"那個時候是我第一次知道害怕到腿軟這句話的真正意思。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"혼자서 마주친 3종 침식체는...... 정말 크고...... 정말 무서웠거든요.","JPN":"一人で遭遇した第3種侵食体は……本当に大きくて……本当に怖かったんです。","ENG":"That Category 3 I faced all by myself... was too big... and too scary.","TWN":"一個人面對3類侵蝕體……真的很巨大……很可怕。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"덩실이를 짚고 있지 않았으면 아마 그 자리에서 주저앉았을 거예요.","JPN":"ふわりを握っていなかったら、たぶんその場で座り込んでしまったと思います。","ENG":"I would have collapsed on the spot if I didn't have Dangler to keep me propped up.","TWN":"如果不是拿著鐮刀，可能我會當場嚇得坐在地上。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"떨지 마...... 대시......! 떨면 안 돼......!","JPN":"怯えないで……ダッシュ……！　怯えちゃダメなの……！","ENG":"Don't tremble... Dash! Stop shaking!","TWN":"別抖……黛西……！別抖……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니도 최선을 다하고 있을 거야! 무서워하지 마......!","JPN":"リタお姉ちゃんだって今頃最善を尽くしている！　怖がることない……！","ENG":"Rita's probably doing her best right now too! Don't be scared!","TWN":"麗塔姐姐會盡力的！別害怕……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"시간만 끄는 거야! 불가능한 건 아니잖아!","JPN":"時間だけ稼げばいいから！　不可能なことでもない！","ENG":"All I need to do is buy some time! It's not impossible!","TWN":"只要好好拖延時間罷了！這不是不可能的事！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"3종 침식체라도...... 할 수 있어! 대시!","JPN":"第3種侵食体の相手でも……私ならできる、ダッシュ！","ENG":"Even if it's a Category 3... You can do this! Dash!","TWN":"即使是3類侵蝕體……你也可以的！黛西！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Ngh!","TWN":"咳？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ELECTRIC_BIG"},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"좋아...... 거의 다 끝났어.","JPN":"よし……ほぼ終わった。","ENG":"Good... I'm almost done.","TWN":"好……差不多都搞定了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"망할 꼬맹이, 결국 끝까지 내 말을 듣는 법이 없지.","JPN":"あのクソガキ、結局最後まで私の言うことを聞かなかったな。","ENG":"That darn kid never listens to me.","TWN":"該死的小鬼，真是一點也不乖。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"매번 자기가 친 사고를 뒷수습하면 바보처럼 웃기나 하고......","JPN":"いつもあいつがやらかしたことの後始末をしてると、バカみたいヘラヘラしてて……","ENG":"Always smiling like a dork while I clean up after her...","TWN":"每次交代她收拾殘局，都只會像笨蛋一樣傻笑……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ELECTRIC_BIG"},{"id":"L34_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나도 이제 지긋지긋해. 호라이즌.","JPN":"もううんざりなんだ、ホライズン。","ENG":"I'm sick and tired of it now, Horizon.","TWN":"現在我也厭倦這樣了，地平線。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 꼬맹이는 언젠가 한 번 크게 당해 봐야 돼.","JPN":"あのガキはいつか本当に痛い目にあわないとだめだ。","ENG":"Someone's got to teach the kid a brutal lesson one day.","TWN":"那個小鬼一定要狠狠的跌倒一次才行。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래야 자기가 뭘 얼마나 감당할 수 있나 깨닫겠지.","JPN":"そうすれば自分が何をどこまで対処できるか、気付くだろう。","ENG":"Then she'll finally realize what she can handle.","TWN":"那樣她才會知道自己有幾兩重。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하지만......","JPN":"だけど……","ENG":"Having said that...","TWN":"但是……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇다고 이런 데서 죽으란 뜻은 아냐.","JPN":"だからって、こんなところで死んでほしくはない。","ENG":"I never meant for her to die in a dumpster like this.","TWN":"我不是要她死在這個地方的意思。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"됐다......! 비상 동력도 한동안은 버텨 주겠어!","JPN":"できた……！　非常動力もしばらくは持つ！","ENG":"There! The emergency power should hold for the time being!","TWN":"算了……！緊急動力也能堅持一段時間吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 구조 요청은 관리국이 지정한 단파 회선을 통해 송신 중이다!","JPN":"この救助要請は管理局が指定した短波回線から送信している！","ENG":"May Day, May Day! This is a May Day signal broadcast on the Administration-designated shortwave line!","TWN":"這個求救信號正在通過管理局指定的短波線路發送！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이면세계에서 조난자 2명 발생! 좌표 기록을 동시에 발신하고 있다!","JPN":"裏世界で遭難者2名が発生！　座標記録を同時に発信している！","ENG":"We have two individuals stranded in the Counterside! I'm sending out the coordinates along with this message!","TWN":"異界發現2名遇難者！正在發送座標記錄！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"반복한다! 이 구조 요청은 관리국이 지정한 단파 회선을 통해 송신 중이다!","JPN":"繰り返す！　この救助要請は管理局が指定した短波回線から送信している！","ENG":"I repeat! This is a May Day broadcast on the Administration-designated shortwave line!","TWN":"重複！這個求救信號正在通過管理局指定的短波線路發送！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그러니까 아무라도 응답해! 어서!","JPN":"誰でもいいから答えろ！　頼む！","ENG":"Come in! Anyone! Hurry!","TWN":"快應答！快！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"빌어먹을......","JPN":"ちくしょう……","ENG":"Darn it...","TWN":"可惡……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나도 알아...... 길이 닫힌 지금은 이런 고심도 좌표에서 구조를 바라는 게 멍청하다는 거......","JPN":"私も知ってるよ……道が塞がれた今、こんな高深度座標で救助を望むのが愚かだということくらい……","ENG":"I know... With the way back sealed, it's tough to imagine anyone would come get us this deep...","TWN":"我也知道……通道已經關閉，費盡心機用座標求救是愚蠢的……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"함선이 두 척이나 침몰했어도...... 어떤 괴물이 도사리고 있을지 모르니까 쉽게 못 올 거라고......","JPN":"艦船が2隻も沈没しても……どんな怪物が潜んでいるかわからないから、簡単には来られないということを……","ENG":"Even with two ships down... They'll think twice about sending out a rescue crew, not knowing what threats lurks here...","TWN":"艦船已經沉沒了兩艘……不知道這裡還隱藏著什麼怪物，要找來救援並不容易……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이한테...... 어떻게 솔직하게 말하란 말이야......!","JPN":"あの子に……正直に言えるわけないだろ……！","ENG":"How the hell... am I supposed to tell the kid this?!","TWN":"這些話要怎麼……對小鬼說啊……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래도 부탁이니까, 아무라도 좋으니까 응답해 줘......","JPN":"頼むから、誰でもいいから答えてくれ……","ENG":"But still... please come in... anyone...","TWN":"就算這樣，也拜託了，什麼都好，請回答我……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐든지 하겠어...... 그러니 제발, 제발 저 꼬맹이만은......","JPN":"何でもするから……頼む。どうか、どうかあの子だけは……","ENG":"I'll do anything you ask... So please save the kid... just the kid...","TWN":"我做什麼都可以……所以拜託了，拜託一定要把那個孩子……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>역시, 하찮은 미물에게는 절망하는 꼴이 어울리는구나.</color>","JPN":"<color=#ff3636>やはり、下等な微物が故、絶望する姿がとても似合うではないか。</color>","ENG":"<color=#ff3636>Indeed, despair is a habiliment best worn by ye petty mortals.</color>","TWN":"<color=#ff3636>果然，螻蟻最適合這種絕望的樣子了。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 말투는......","JPN":"この口調は……","ENG":"Who's the Shakespeare?","TWN":"這語氣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"설마, 꿈에서 본 그림자?","JPN":"まさか、夢でみたシャドウ？","ENG":"Could it be the Shadow from the dream?","TWN":"難道，是夢裡看到的暗影？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇다. 어리석은 자여.","JPN":"うむ、愚者よ。","ENG":"Aye, 'tis I. Ye fool.","TWN":"是的，愚蠢的人類。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"기뻐하라. 왕의 축복 아래 새롭게 해방될 자를 맞이하고자 내가 여기 임하였도다.","JPN":"喜ぶがいい。王の祝福の下、新たに解放される者を迎えるために余がここに降臨した。","ENG":"Rejoice. For I have arrived to welcome the one to be liberated by the queen's blessing.","TWN":"高興吧，在王的祝福下，我來這裡迎接被解放的新人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};